# ---------------------------------------------------------------------------
# Internal interpolation helpers
# ---------------------------------------------------------------------------

def _interp_liq(re_liq, b):
    """
    LIQFLAG=1 linear interpolation for one re value and one band b (0-indexed).

    Mirrors Fortran exactly:
        INDEX = RADLIQ - 1.5
        IF (INDEX .EQ. 0) INDEX = 1
        IF (INDEX .EQ. 58) INDEX = 57
        FINT = RADLIQ - 1.5 - INDEX

    Returns (ext, ssa, asy).
    """
    idx = int(re_liq - 1.5)
    if idx == 0:
        idx = 1
    if idx == 58:
        idx = 57
    fint = re_liq - 1.5 - float(idx)
    # Fortran 1-based index idx -> Python idx-1
    i0 = idx - 1
    i1 = idx
    ext = EXTLIQ1[i0, b] + fint * (EXTLIQ1[i1, b] - EXTLIQ1[i0, b])
    ssa = SSALIQ1[i0, b] + fint * (SSALIQ1[i1, b] - SSALIQ1[i0, b])
    asy = ASYLIQ1[i0, b] + fint * (ASYLIQ1[i1, b] - ASYLIQ1[i0, b])
    return ext, ssa, asy


def _interp_ice2(re_ice, b):
    """
    ICEFLAG=2 linear interpolation for one re value and one band b (0-indexed).

    Mirrors Fortran exactly:
        FACTOR = (RADICE - 2.) / 3.
        INDEX  = INT(FACTOR)
        IF (INDEX .EQ. 43) INDEX = 42
        FINT   = FACTOR - FLOAT(INDEX)

    Returns (ext, ssa, asy).
    """
    factor = (re_ice - 2.0) / 3.0
    idx = int(factor)
    if idx >= 43:
        idx = 42
    if idx < 0:
        idx = 0
    fint = factor - float(idx)
    # Guard against overshooting at upper bound
    if idx == 42:
        fint = 0.0
    ext = EXTICE2[idx, b] + fint * (EXTICE2[idx + 1 if idx < 42 else idx, b] - EXTICE2[idx, b])
    ssa = SSAICE2[idx, b] + fint * (SSAICE2[idx + 1 if idx < 42 else idx, b] - SSAICE2[idx, b])
    asy = ASYICE2[idx, b] + fint * (ASYICE2[idx + 1 if idx < 42 else idx, b] - ASYICE2[idx, b])
    return ext, ssa, asy


def _interp_ice3(dge, b):
    """
    ICEFLAG=3 linear interpolation for one dge value and one band b (0-indexed).

    Mirrors Fortran exactly:
        FACTOR = (RADICE - 2.) / 3.
        INDEX  = INT(FACTOR)
        IF (INDEX .EQ. 46) INDEX = 45
        FINT   = FACTOR - FLOAT(INDEX)

    Returns (ext, ssa, asy).
    """
    factor = (dge - 2.0) / 3.0
    idx = int(factor)
    if idx >= 46:
        idx = 45
    if idx < 0:
        idx = 0
    fint = factor - float(idx)
    if idx == 45:
        fint = 0.0
    ext = EXTICE3[idx, b] + fint * (EXTICE3[idx + 1 if idx < 45 else idx, b] - EXTICE3[idx, b])
    ssa = SSAICE3[idx, b] + fint * (SSAICE3[idx + 1 if idx < 45 else idx, b] - SSAICE3[idx, b])
    asy = ASYICE3[idx, b] + fint * (ASYICE3[idx + 1 if idx < 45 else idx, b] - ASYICE3[idx, b])
    return ext, ssa, asy


# ---------------------------------------------------------------------------
# Public API
# ---------------------------------------------------------------------------

def cloud_optical_depth(
    frac,
    lwp_gm2,
    re_liq_um,
    iwp_gm2,
    re_ice_um,
    iceflag=2,
):
    """
    Compute SW cloud optical properties for 14 bands (Fortran 16-29).

    Parameters
    ----------
    frac      : array_like, shape (nlayers,)
        Cloud fraction [0,1].  NaN treated as 0.
    lwp_gm2   : array_like, shape (nlayers,)
        Liquid water path [g m^-2].  NaN treated as 0.
    re_liq_um : array_like, shape (nlayers,)
        Liquid droplet effective radius [µm] (valid 1.5..60 µm).
        NaN or <= 0 -> skip liquid contribution.
    iwp_gm2   : array_like, shape (nlayers,)
        Ice water path [g m^-2].  NaN treated as 0.
    re_ice_um : array_like, shape (nlayers,)
        Ice effective radius or generalized effective size [µm].
        For iceflag=2: valid 5..131 µm.
        For iceflag=3: valid 5..140 µm.
        NaN or <= 0 -> skip ice contribution.
    iceflag   : int
        2 (Streamer spherical, default) or 3 (Fu 1996 hexagonal).

    Returns
    -------
    tau_cloud  : ndarray, shape (nlayers, 14)
        Delta-m-unscaled total cloud extinction optical depth.
    ssa_cloud  : ndarray, shape (nlayers, 14)
        Combined single-scattering albedo.
    g_cloud    : ndarray, shape (nlayers, 14)
        Combined asymmetry parameter.
    frac_clean : ndarray, shape (nlayers,)
        Cloud fraction with NaN replaced by 0.
    """
    frac      = np.where(np.isnan(frac),      0.0, np.asarray(frac,      dtype=np.float64))
    lwp_gm2   = np.where(np.isnan(lwp_gm2),   0.0, np.asarray(lwp_gm2,   dtype=np.float64))
    re_liq_um = np.where(np.isnan(re_liq_um), 0.0, np.asarray(re_liq_um, dtype=np.float64))
    iwp_gm2   = np.where(np.isnan(iwp_gm2),   0.0, np.asarray(iwp_gm2,   dtype=np.float64))
    re_ice_um = np.where(np.isnan(re_ice_um), 0.0, np.asarray(re_ice_um, dtype=np.float64))

    nlayers = len(frac)
    NBANDS  = 14

    tau_cloud = np.zeros((nlayers, NBANDS))
    ssa_cloud = np.zeros((nlayers, NBANDS))
    g_cloud   = np.zeros((nlayers, NBANDS))

    for lay in range(nlayers):
        if frac[lay] <= 0.0:
            continue

        # ------------------------------------------------------------------ #
        # Liquid phase (LIQFLAG=1, Hu & Stamnes)
        # ------------------------------------------------------------------ #
        tau_liq = np.zeros(NBANDS)
        ssa_liq = np.zeros(NBANDS)
        g_liq   = np.zeros(NBANDS)

        liq_ok = (lwp_gm2[lay] > 0.0 and re_liq_um[lay] > 0.0)
        if liq_ok:
            re = float(re_liq_um[lay])
            # Clamp to valid range (mirrors Fortran STOP checks replaced by clamp)
            re = max(1.5, min(re, 60.0))
            for b in range(NBANDS):
                ext, ssa, asy = _interp_liq(re, b)
                tau_liq[b] = lwp_gm2[lay] * ext
                ssa_liq[b] = ssa
                g_liq[b]   = asy

        # ------------------------------------------------------------------ #
        # Ice phase (ICEFLAG=2 or 3)
        # ------------------------------------------------------------------ #
        tau_ice = np.zeros(NBANDS)
        ssa_ice = np.zeros(NBANDS)
        g_ice   = np.zeros(NBANDS)

        ice_ok = (iwp_gm2[lay] > 0.0 and re_ice_um[lay] > 0.0)
        if ice_ok:
            re = float(re_ice_um[lay])
            if iceflag == 2:
                re = max(5.0, min(re, 131.0))
                for b in range(NBANDS):
                    ext, ssa, asy = _interp_ice2(re, b)
                    tau_ice[b] = iwp_gm2[lay] * ext
                    ssa_ice[b] = ssa
                    g_ice[b]   = asy
            elif iceflag == 3:
                re = max(5.0, min(re, 140.0))
                for b in range(NBANDS):
                    ext, ssa, asy = _interp_ice3(re, b)
                    tau_ice[b] = iwp_gm2[lay] * ext
                    ssa_ice[b] = ssa
                    g_ice[b]   = asy
            else:
                raise ValueError(f"iceflag must be 2 or 3, got {iceflag}")

        # ------------------------------------------------------------------ #
        # Combine liquid and ice contributions
        # ------------------------------------------------------------------ #
        NSTR = 16   # number of DISORT streams (for delta-M scaling)
        tau_total = tau_liq + tau_ice
        for b in range(NBANDS):
            if tau_total[b] > 0.0:
                ssa_c = (ssa_liq[b] * tau_liq[b] + ssa_ice[b] * tau_ice[b]) / tau_total[b]
                denom = max(ssa_c * tau_total[b], 1.0e-30)
                g_c   = (g_liq[b] * ssa_liq[b] * tau_liq[b] +
                          g_ice[b] * ssa_ice[b] * tau_ice[b]) / denom
            else:
                ssa_c = 0.0
                g_c   = 0.0
            # Delta-M scaling (Wiscombe 1977)
            f_dm   = g_c ** NSTR
            tau_dm = tau_total[b] * (1.0 - ssa_c * f_dm)
            denom_dm = max(1.0 - ssa_c * f_dm, 1.0e-30)
            ssa_dm = ssa_c * (1.0 - f_dm) / denom_dm
            tau_cloud[lay, b] = tau_dm
            ssa_cloud[lay, b] = ssa_dm
            g_cloud  [lay, b] = g_c

    return tau_cloud, ssa_cloud, g_cloud, frac
